DROP TABLE IF EXISTS `tb_data_source`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_data_source` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(64) COLLATE utf8mb4_general_ci NOT NULL COMMENT '数据源名称',
  `description` varchar(500) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '描述，给AI看的',
  `url` varchar(500) COLLATE utf8mb4_general_ci NOT NULL COMMENT '接口URL',
  `method` varchar(8) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'GET' COMMENT 'HTTP方法',
  `params_schema` json DEFAULT NULL COMMENT '参数定义 {"param":{"type":"int","desc":"..."}}',
  `timeout_ms` int NOT NULL DEFAULT '10000' COMMENT '超时毫秒',
  `retry_times` tinyint NOT NULL DEFAULT '3' COMMENT '重试次数',
  `sort_order` int NOT NULL DEFAULT '0' COMMENT '排序',
  `status` tinyint unsigned NOT NULL DEFAULT '1' COMMENT '1=启用 0=停用',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='数据源配置(数据源导航器)';
