INSERT INTO `tb_data_source` VALUES (1,'意图案例库','包含所有意图名、关键词列表、触发条件，用于双判断意图识别中的关键词匹配阶段','http://localhost:8081/api/agent/intent-cases','GET','{}',10000,3,1,1,'2026-05-02 17:44:27','2026-05-02 17:44:27'),(2,'策略规则库','包含推荐策略规则（过滤、加权、排序、排除），用于LLM智能选择阶段。scene参数：food_recommend/scene_query/guide','http://localhost:8081/api/agent/strategy-rules','GET','{\"scene\": {\"desc\": \"场景\", \"type\": \"string\"}}',10000,3,2,1,'2026-05-02 17:44:27','2026-05-02 17:44:27'),(3,'标签词库','根据关键词或分类获取匹配的标签列表（含标签名、类别、同义词）','http://localhost:8081/api/agent/tags','GET','{\"keyword\": {\"desc\": \"搜索关键词\", \"type\": \"string\"}, \"category\": {\"desc\": \"标签大类\", \"type\": \"string\"}}',10000,3,3,1,'2026-05-02 17:44:27','2026-05-02 17:44:27'),(4,'商家推荐数据','根据标签ID列表获取关联的商家信息（名称、商圈、地址、人均、评分、图片）','http://localhost:8081/api/agent/shops/by-tags','GET','{\"tagIds\": {\"desc\": \"标签ID列表，逗号分隔\", \"type\": \"string\"}}',10000,3,4,1,'2026-05-02 17:44:27','2026-05-02 17:44:27'),(5,'笔记推荐数据','根据标签ID列表获取关联的探店笔记（标题、内容摘要、点赞数、图片）','http://localhost:8081/api/agent/blogs/by-tags','GET','{\"tagIds\": {\"desc\": \"标签ID列表，逗号分隔\", \"type\": \"string\"}}',10000,3,5,1,'2026-05-02 17:44:27','2026-05-02 17:44:27');
/*!40000 ALTER TABLE `tb_data_source` ENABLE KEYS */;
UNLOCK TABLES;

