INSERT INTO `tb_intent_case` VALUES (1,'美食推荐','food','[\"吃什么\", \"好吃的\", \"美食\", \"餐厅\", \"附近有什么\", \"哪家好吃\", \"想吃\", \"聚餐\", \"约会\", \"请客\", \"推荐餐厅\", \"推荐吃的\", \"推荐美食\", \"推荐火锅\", \"推荐川菜\", \"推荐日料\", \"推荐烤肉\", \"推荐烧烤\", \"推荐粤菜\"]','用户想要寻找餐厅/美食推荐，可能带有预算、位置、菜系、场景等条件','[{\"input\": \"附近有什么好吃的川菜\", \"output\": \"1\"}, {\"input\": \"想找个适合约会的餐厅\", \"output\": \"1\"}]',0,10,1,'2026-05-02 17:44:27','2026-05-03 08:40:03'),(2,'景点查询','scene','[\"去哪玩\", \"景点\", \"好玩的地方\", \"打卡\", \"周末去哪\", \"旅游\", \"逛逛\", \"风景\", \"附近景点\", \"推荐景点\", \"游玩\", \"周边游\", \"一日游\"]','用户想要查询景点/游玩地点，可能带有位置、类型、距离等条件','[{\"input\": \"周末想去哪逛逛\", \"output\": \"2\"}, {\"input\": \"有什么适合拍照的地方\", \"output\": \"2\"}]',0,9,1,'2026-05-02 17:44:27','2026-05-03 08:40:03'),(3,'攻略查看','guide','[\"攻略\", \"怎么玩\", \"怎么去\", \"路线\", \"推荐行程\", \"必去\", \"必吃\", \"避坑\", \"博客\", \"笔记\", \"探店\", \"帖子\", \"日记\", \"分享\", \"点评\", \"测评\", \"推荐博客\", \"推荐笔记\"]','用户想看攻略/笔记，找别人写的推荐内容','[{\"input\": \"有没有朝阳区的探店笔记\", \"output\": \"3\"}, {\"input\": \"避坑指南有没有\", \"output\": \"3\"}]',0,11,1,'2026-05-02 17:44:27','2026-05-03 08:40:03'),(4,'其他','other','[]','无法匹配以上意图时归类到此','[{\"input\": \"今天天气怎么样\", \"output\": \"4\"}]',0,0,1,'2026-05-02 17:44:27','2026-05-02 17:44:27');
