--
-- Table structure for table `tb_shop_tag`
--

DROP TABLE IF EXISTS `tb_shop_tag`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_shop_tag` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `shop_id` bigint unsigned NOT NULL COMMENT '商铺ID -> tb_shop.id',
  `tag_id` int unsigned NOT NULL COMMENT '标签ID -> tb_tag.id',
  `source` tinyint NOT NULL DEFAULT '0' COMMENT '0=人工标注 1=AI自动打标',
  `confidence` float NOT NULL DEFAULT '1' COMMENT 'AI打标签的置信度',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_shop_tag` (`shop_id`,`tag_id`),
  KEY `idx_shop_id` (`shop_id`),
  KEY `idx_tag_id` (`tag_id`)
) ENGINE=InnoDB AUTO_INCREMENT=141 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商铺-标签关联';
/*!40101 SET character_set_client = @saved_cs_client */;

